INSERT INTO packs (id, name, version, author, description, sha256, signature, signed_by, readme, created_at, updated_at) VALUES
('deep-work-starter', 'Deep Work Starter', '0.1.0', 'focalpoint-team', 'A minimal starter pack with a single deep-work block rule. Mirrors the app''s built-in deep-work template.', '3de347bad17db4440cf4c1512a0642476548a5107ef68d6c2efd436f656ed234', 'Guy3iRCuKMJv8CuFz1aj500DkjBJodS0Hp/5fBFTNFAsa/R3Hw/J6+htymUvK4WXsLZNCUZrsvHQd2W5Uf34Ag==', 'c742e5e5fa536e56', 'FocalPoint''s most-used starter pack. Rules: social-media block during deep-work sessions. Recommended for teams and individuals adopting focus discipline.', '2026-04-24 00:00:00', '2026-04-24 00:00:00'),
('student-canvas', 'Student Canvas', '0.1.0', 'focalpoint-team', 'Reward credits on assignment submission and good grades; block social apps when an assignment is due within 24h. Built for Canvas LMS users.', '2eb24c64a2a6129db8e756d189bccfc9ee20c7783fb6f1e67781652fd99f7778', 'PSBxlAinfw6v4ojNnyWTdkqsfQexq9LzDJMuPPRrm5CqEm3b2oZBC7qI4R4nm4gmr3XctFLY2+hQJgTGQgkvCQ==', 'c742e5e5fa536e56', 'For university students using Canvas LMS. Integrates with Canvas events and calendar. Rules: assignment-due alerts, reward completion, block during deadline windows.', '2026-04-24 00:00:00', '2026-04-24 00:00:00'),
('dev-flow', 'Developer Flow', '0.1.0', 'focalpoint-team', 'Credit meaningful code output (merged PRs, closed issues), streak daily commits, gentle intervention when you''re bouncing between repos.', '15166d01490a5bfbc02be3a120d74b078960bd0609bd5f4e40168f41f43d1768', 'ptpuYbR2JmZh/+Ds5G/8mqk0oph4F4UFsBm1WMCe54knh6l6y/Ycshp01gRxi5YCT1paC8I6zmVjFwUudiqWAQ==', 'c742e5e5fa536e56', 'Tailored for software engineers. Integrates GitHub commits, PR merges, and issue closure. Rules: daily commit streaks, PR reward, context-switch detection.', '2026-04-24 00:00:00', '2026-04-24 00:00:00'),
('sleep-hygiene', 'Sleep Hygiene', '0.1.0', 'focalpoint-team', 'Hard lockdown on entertainment apps 23:00–06:00, streak rewards for reporting ≥7h sleep, gentle intervention when sleep debt grows.', 'afb84b53c24db025495b5a193cbb443b11cc4e55622b65de419690a4e8263d4e', 'rVXXzXkF+fZNHZ1CS3VQhPnlYnQ/hQdTO+VtvvLpqR4fnruazGjd/UH8oDb8aQF5bl7afWvvZ8guDS037OXFCA==', 'c742e5e5fa536e56', 'Health-focused pack. Enforces night-time app restrictions. Rules: entertainment lockdown, sleep tracking, wellness streaks, gradual intervention on sleep debt.', '2026-04-24 00:00:00', '2026-04-24 00:00:00'),
('gym-routine', 'Gym Routine', '0.1.0', 'focalpoint-team', 'Event-triggered credits for completed workouts, block social during scheduled sessions, maintain weekly streak consistency.', '61ffd785255e2f1d4a0cf41622db67ff8a6d11111abe34ddd659665f1d3c4c1e', 'Kd+fLew5qURjZViVzKyyMhULgJx4Jxl/SxwRhE1uM/3BO8GvNzgWFzOAJwnYC0WFE076ap1+gvwlxcaBY6ThBQ==', 'c742e5e5fa536e56', 'Fitness pack for gym-goers. Calendar integration for scheduled workouts. Rules: workout rewards, session isolation, weekly consistency streaks.', '2026-04-24 00:00:00', '2026-04-24 00:00:00'),
('reading-habit', 'Reading Habit', '0.1.0', 'focalpoint-team', 'Schedule-triggered reading-time suggestions with daily streak tracking. Credit grants on highlight creation (Readwise integration).', 'a18c6bb905838f64323d8c2f4e30418e36ca200d178a0a9fb4627b49f5de4e56', 'Qftph//WtWLRMZdg0MS+KjUaZ2gOjvaV79FQcrK5bSHMjv7rLk1XXg2qZBK2CE2/OPI5LlXwwe6O9PeU/Hi2Dw==', 'c742e5e5fa536e56', 'For avid readers. Integrates with Readwise and reading calendars. Rules: daily reading slots, highlight-based rewards, streak maintenance.', '2026-04-24 00:00:00', '2026-04-24 00:00:00'),
('research-writing', 'Research & Writing', '0.1.0', 'focalpoint-team', 'Morning deep-work blocks (9–11am weekdays) with hard social block. Event-triggered credits on code commits and document edits. Deadline lockdown when calendar has a ''deadline'' event within 24h.', '3bec303fa5ce485239562ebfc0b5b46b72b736b2b360efb5cc02db708bdaab29', 'xttWfnRqb58Qp7ElApdABOR+ue1BTyHf5rdK2WEN9y6VNBbRw7esTIr5jQr27OiShspw6IAHYrtv5MbEtSsUDA==', 'c742e5e5fa536e56', 'For academics and researchers. Morning focus blocks with deadline awareness. Rules: peak-time blocking, commit/edit rewards, deadline lockdown, social restrictions.', '2026-04-24 00:00:00', '2026-04-24 00:00:00');
